// src/pages/PrivacyPolicy.jsx
import React, { useState, useEffect, useRef } from 'react';
import './PrivacyPolicy.css';

const LAST_UPDATED = 'April 1, 2025';
const EFFECTIVE_DATE = 'April 1, 2025';
const COMPANY_NAME = 'Chagans Technologies Limited';
const REGISTERED_OFFICE = 'SCO-4, Dayal Bagh, Sector-39, Faridabad – 121009, Haryana';
const PRIVACY_EMAIL = 'privacy@oncallfuel.in';
const SUPPORT_EMAIL = 'support@oncallfuel.in';

const SECTIONS = [
  {
    id: 'intro',
    icon: '🔒',
    title: 'Introduction',
    content: [
      {
        type: 'highlight',
        variant: 'green',
        icon: '🛡️',
        text: 'OnCallFuel is committed to protecting your personal information and ensuring complete transparency about how your data is collected, used, and safeguarded.',
      },
      {
        type: 'para',
        text: `This Privacy Policy applies to all users of the OnCallFuel platform — including individuals, households, businesses, hotels, and corporate customers — who access our services through the website (www.oncallfuel.in), mobile application, or any other channel operated by ${COMPANY_NAME}, a company having its registered office at ${REGISTERED_OFFICE}.`,
      },
      {
        type: 'para',
        text: 'By visiting and/or using the OnCallFuel platform, you agree to the terms of this Privacy Policy, and it shall be deemed that you have read, accepted, and consented to the practices described herein. If you do not agree to any term contained in this Privacy Policy, please immediately cease your use of the platform.',
      },
      {
        type: 'para',
        text: 'OnCallFuel reserves the right to modify this Privacy Policy at any time. Any changes will be posted on our platform and will become effective from the date of such posting. Continued use of the platform after any modification constitutes your acceptance of the revised terms.',
      },
      {
        type: 'heading',
        text: 'Legal Framework',
      },
      {
        type: 'list',
        items: [
          'Section 43A of the Information Technology Act, 2000',
          'Regulation 4 of the Information Technology (Reasonable Security Practices and Procedures and Sensitive Personal Data or Information) Rules, 2011',
          'Regulation 3(1) of the Information Technology (Intermediaries Guidelines) Rules, 2011',
          'Applicable provisions of the Digital Personal Data Protection Act, 2023 (DPDPA)',
          'Indian Contract Act, 1872',
        ],
      },
    ],
  },
  {
    id: 'data-collected',
    icon: '📋',
    title: 'Data We Collect',
    content: [
      { type: 'heading', text: 'Information You Provide Actively' },
      {
        type: 'cards',
        items: [
          { icon: '👤', title: 'Identity Data', desc: 'Full name, date of birth (for age verification), government-issued ID (required for bulk orders above ₹25,000).' },
          { icon: '📞', title: 'Contact Data', desc: 'Mobile number, email address, WhatsApp number, registered address, and delivery addresses.' },
          { icon: '🚗', title: 'Vehicle Data', desc: 'Vehicle registration number, make, model, and fuel type — provided voluntarily for emergency delivery requests.' },
          { icon: '💳', title: 'Payment Data', desc: 'UPI ID, last 4 digits of card (tokenized), bank name. Full card or account details are never stored by OnCallFuel.' },
          { icon: '🏢', title: 'Business Data', desc: 'GST number, company name, business address, authorized contact details for B2B and corporate accounts.' },
          { icon: '💬', title: 'Communication Data', desc: 'Messages via chat support, email inquiries, call recordings (where legally required), and feedback responses.' },
        ],
      },
      { type: 'heading', text: 'Information Collected Automatically (Passive Collection)' },
      {
        type: 'para',
        text: 'OnCallFuel may use tracking tools such as Google Analytics, browser cookies, and similar technologies to passively collect information about your usage of our platform. This information may be used for internal research to understand user demographics, interests, and behaviour.',
      },
      {
        type: 'list',
        items: [
          'Device identifiers: IP address, device type, OS version, app version, browser type',
          'Location data: GPS coordinates (with your permission) at time of order placement for delivery routing',
          'Usage data: pages viewed, features used, session duration, click patterns on the platform',
          'Transaction logs: order history, delivery timestamps, cancellation records',
          'Referral data: URL of the website visited just before or after visiting OnCallFuel',
          'Cookies and similar tracking technologies (see our Cookie Policy below)',
        ],
      },
      {
        type: 'highlight',
        variant: 'amber',
        icon: '⚠️',
        text: 'You acknowledge that all information provided by you on the platform is submitted voluntarily and at your own risk. You are solely responsible for ensuring the accuracy and completeness of the information provided.',
      },
    ],
  },
  {
    id: 'how-we-use',
    icon: '🎯',
    title: 'How We Use Your Data',
    content: [
      {
        type: 'para',
        text: 'Information collected by OnCallFuel shall be used only for the purposes of providing the Services and shall not be used, sold, transferred, or rented in any manner not set out in this Privacy Policy.',
      },
      {
        type: 'table',
        headers: ['Purpose', 'Data Used', 'Legal Basis'],
        rows: [
          ['Processing and fulfilling fuel delivery orders', 'Name, address, contact, payment', 'Contract performance'],
          ['Verifying identity and preventing fraud', 'ID, device data, transaction history', 'Legal obligation / Legitimate interest'],
          ['Sending order updates and delivery notifications', 'Mobile number, email address', 'Contract performance'],
          ['Customer support and dispute resolution', 'All order-related data', 'Contract performance / Legal obligation'],
          ['Improving platform features and user experience', 'Usage data, anonymized feedback', 'Legitimate interest'],
          ['Marketing and promotional communications (opt-in)', 'Email, mobile number', 'Consent (opt-in only)'],
          ['Security and fraud prevention', 'Device data, transaction logs', 'Legitimate interest / Legal obligation'],
          ['Compliance with legal and regulatory requirements', 'Identity, transaction data', 'Legal obligation'],
          ['Anonymized analytics and business intelligence', 'Aggregated usage data', 'Legitimate interest'],
        ],
      },
    ],
  },
  {
    id: 'sharing',
    icon: '🤝',
    title: 'Data Sharing & Disclosure',
    content: [
      {
        type: 'para',
        text: 'OnCallFuel does not sell your personal data to any third party. We share your data only in the following limited and necessary circumstances:',
      },
      {
        type: 'list',
        items: [
          'Delivery Partners: Name, address, and mobile number shared with field delivery personnel solely to fulfil your order',
          'Payment Processors: Transaction details shared with PCI-DSS compliant payment gateways (e.g., Razorpay, PayU)',
          'SMS / Communication Providers: Mobile number shared with licensed telecom providers for OTPs and order notifications',
          'Cloud Infrastructure: Data stored on AWS / Google Cloud servers located in India',
          'Analytics Partners: Only anonymized, aggregated usage data — no personally identifiable information',
          'Law Enforcement: When required by court order, subpoena, or applicable Indian law',
          'Business Transfers: In case of merger, acquisition, or asset sale, with appropriate confidentiality protections',
        ],
      },
      {
        type: 'highlight',
        variant: 'green',
        icon: '✅',
        text: 'We never share your personal data with advertisers, data brokers, or third-party marketing companies without your explicit prior consent. OnCallFuel is not responsible for the privacy practices of third-party websites linked from our platform.',
      },
    ],
  },
  {
    id: 'retention',
    icon: '🗃️',
    title: 'Data Retention',
    content: [
      {
        type: 'para',
        text: 'Even if you delete your account on the platform, OnCallFuel may retain your information for a period of time until it can be removed from its servers and to comply with applicable legal obligations.',
      },
      {
        type: 'table',
        headers: ['Data Type', 'Retention Period', 'Reason'],
        rows: [
          ['Order and transaction records', '7 years', 'Tax and accounting compliance (IT Act)'],
          ['Account profile data', 'Duration of account + 2 years', 'Legal and dispute resolution'],
          ['Delivery GPS logs', '90 days', 'Dispute resolution and quality assurance'],
          ['Payment tokens', '5 years', 'Financial audit requirements'],
          ['Customer support communications', '2 years from last interaction', 'Quality assurance and legal purposes'],
          ['Marketing preferences (opt-in/out)', 'Until withdrawn by user', 'Consent management'],
          ['App usage and analytics data', '1 year (anonymized)', 'Product improvement'],
          ['Call recordings', '90 days', 'Quality and legal compliance'],
        ],
      },
      {
        type: 'para',
        text: 'After the applicable retention period, data is securely deleted or anonymized. You may request early deletion of your data (see "Your Rights" section below), subject to mandatory legal retention obligations.',
      },
    ],
  },
  {
    id: 'security',
    icon: '🛡️',
    title: 'Data Security',
    content: [
      {
        type: 'para',
        text: 'OnCallFuel implements industry-standard technical and organisational measures to protect your personal data from unauthorized access, loss, or misuse:',
      },
      {
        type: 'cards',
        items: [
          { icon: '🔐', title: 'Encryption', desc: 'All data in transit is encrypted using TLS 1.2+. Sensitive data at rest is encrypted using AES-256 standards.' },
          { icon: '🏗️', title: 'Infrastructure', desc: 'Hosted on ISO 27001 certified cloud infrastructure with automated threat detection and DDoS protection.' },
          { icon: '👥', title: 'Access Control', desc: 'Role-based access ensures staff only access data strictly necessary for their job functions. Employees do not have access to user passwords.' },
          { icon: '🔍', title: 'Security Audits', desc: 'Regular third-party security audits, penetration testing, and vulnerability assessments are conducted.' },
          { icon: '💳', title: 'Payment Security', desc: 'Payment processing is handled via PCI-DSS Level 1 compliant gateways. OnCallFuel never stores full card or bank account details.' },
          { icon: '📱', title: 'App Security', desc: 'Mobile app uses certificate pinning, biometric authentication options, and secure session management.' },
        ],
      },
      {
        type: 'highlight',
        variant: 'amber',
        icon: '🔑',
        text: 'Neither OnCallFuel nor any of its employees will have access to your account password. You are solely responsible for protecting your login credentials. In case of suspected misuse, immediately notify us at support@oncallfuel.in.',
      },
      {
        type: 'highlight',
        variant: 'green',
        icon: '🚨',
        text: 'In the event of a data breach affecting your personal information, OnCallFuel will notify you within 72 hours as required by applicable law, along with steps being taken to mitigate the incident.',
      },
    ],
  },
  {
    id: 'cookies',
    icon: '🍪',
    title: 'Cookies & Tracking',
    content: [
      {
        type: 'para',
        text: 'A cookie is a small file that is placed on your device when you visit a website. OnCallFuel uses cookies and similar technologies to identify page usage patterns, analyze traffic, and improve the functionality of our platform. This information is used only for statistical analysis.',
      },
      {
        type: 'table',
        headers: ['Cookie Type', 'Purpose', 'Duration'],
        rows: [
          ['Essential Cookies', 'Login sessions, order state, security tokens', 'Session'],
          ['Functional Cookies', 'Language/city preferences, recently viewed items', '30 days'],
          ['Analytics Cookies', 'Page views, traffic sources, user behaviour (Google Analytics)', '13 months'],
          ['Performance Cookies', 'Page load times, error tracking', '30 days'],
        ],
      },
      {
        type: 'para',
        text: 'You can manage cookie preferences from your browser settings or our in-app cookie preferences panel. Disabling essential cookies may affect platform functionality. Please note that OnCallFuel does not have control over cookies placed by third-party links on the platform, and does not represent the security of information provided to those third parties.',
      },
      {
        type: 'highlight',
        variant: 'green',
        icon: '✅',
        text: 'OnCallFuel does not use advertising or targeting cookies. We do not share cookie data with advertising networks.',
      },
    ],
  },
  {
    id: 'rights',
    icon: '⚖️',
    title: 'Your Rights',
    content: [
      {
        type: 'para',
        text: 'Under Indian data protection law, including the Information Technology Act, 2000 and the Digital Personal Data Protection Act, 2023, and as per our commitment to privacy-first practices, you have the following rights:',
      },
      {
        type: 'steps',
        items: [
          { step: '01', title: 'Right to Access', desc: 'Request a copy of all personal data we hold about you.' },
          { step: '02', title: 'Right to Correction', desc: 'Request correction of inaccurate or incomplete personal data at any time by notifying us at ' + SUPPORT_EMAIL },
          { step: '03', title: 'Right to Erasure', desc: 'Request deletion of your data, subject to mandatory legal retention requirements.' },
          { step: '04', title: 'Right to Data Portability', desc: 'Receive your data in a structured, machine-readable format.' },
          { step: '05', title: 'Right to Withdraw Consent', desc: 'Withdraw marketing consent at any time without affecting the lawfulness of prior processing.' },
          { step: '06', title: 'Right to Grievance Redressal', desc: 'Lodge a complaint with our Data Protection Officer or the relevant regulatory authority.' },
        ],
      },
      {
        type: 'highlight',
        variant: 'green',
        icon: '📧',
        text: `To exercise any of these rights, email ${PRIVACY_EMAIL} with your registered mobile number and the specific request. We will respond within 30 days.`,
      },
    ],
  },
  {
    id: 'children',
    icon: '👶',
    title: "Children's Privacy",
    content: [
      {
        type: 'para',
        text: 'OnCallFuel services are not directed at individuals under the age of 18. We do not knowingly collect personal data from minors. If we discover that a minor has created an account, we will immediately delete all associated data without notice.',
      },
      {
        type: 'para',
        text: `Parents or guardians who believe their child has provided personal data to OnCallFuel should contact us immediately at ${PRIVACY_EMAIL}.`,
      },
    ],
  },
  {
    id: 'third-party',
    icon: '🔗',
    title: 'Third-Party Sites',
    content: [
      {
        type: 'para',
        text: 'If you click on any link to a third-party website available on the OnCallFuel platform, you may be taken to websites that OnCallFuel does not own or control. This Privacy Policy does not apply to the privacy practices of those websites.',
      },
      {
        type: 'highlight',
        variant: 'amber',
        icon: '⚠️',
        text: 'OnCallFuel shall not be liable for the misuse of your personal information by third-party websites. We recommend reviewing the privacy policies of any third-party sites you visit.',
      },
    ],
  },
  {
    id: 'grievance',
    icon: '📣',
    title: 'Grievance Redressal',
    content: [
      {
        type: 'para',
        text: 'If you have any questions, complaints, or grievances regarding the OnCallFuel platform, its contents, or our Services, you may reach out to our Grievance Officer who will address any complaint raised in accordance with applicable law.',
      },
      {
        type: 'highlight',
        variant: 'green',
        icon: '⏱️',
        text: `All grievances will be acknowledged within 48 hours and resolved within 30 days of receipt. Contact our Grievance Officer at ${SUPPORT_EMAIL}.`,
      },
      {
        type: 'heading',
        text: 'Force Majeure',
      },
      {
        type: 'para',
        text: 'OnCallFuel shall not be responsible for any cessation, interruption, or delay in the performance of its obligations due to earthquake, flood, fire, storm, natural disaster, act of God, war, terrorism, armed conflict, labor strike, lockout, or boycott.',
      },
    ],
  },
  {
    id: 'contact',
    icon: '📬',
    title: 'Contact & DPO',
    content: [
      {
        type: 'para',
        text: 'For all privacy-related questions, requests, or complaints, you may contact our Data Protection Officer or reach us through the following channels:',
      },
      {
        type: 'contact',
        items: [
          { label: 'Data Protection Officer', value: PRIVACY_EMAIL },
          { label: 'General Support', value: SUPPORT_EMAIL },
          { label: 'Company Name', value: COMPANY_NAME },
          { label: 'Registered Office', value: REGISTERED_OFFICE },
          { label: 'Response Time', value: 'Within 30 days' },
          { label: 'Regulatory Authority', value: 'Data Protection Board of India' },
          { label: 'Governing Law', value: 'Laws of India (Information Technology Act, 2000 & DPDPA, 2023)' },
          { label: 'Jurisdiction', value: 'Courts of competent jurisdiction in Faridabad, Haryana' },
        ],
      },
      {
        type: 'para',
        text: 'All notices to OnCallFuel must be sent in writing in the English language via email to the addresses listed above, or by courier to the registered office address.',
      },
    ],
  },
];

const renderContent = (blocks) =>
  blocks.map((block, bi) => {
    if (block.type === 'para')
      return <p key={bi} className="ocf-para">{block.text}</p>;

    if (block.type === 'heading')
      return <h4 key={bi} className="ocf-sub-heading">{block.text}</h4>;

    if (block.type === 'highlight')
      return (
        <div key={bi} className={`ocf-highlight ocf-highlight--${block.variant}`}>
          <span className="ocf-highlight-icon">{block.icon}</span>
          <span>{block.text}</span>
        </div>
      );

    if (block.type === 'list')
      return (
        <ul key={bi} className="ocf-list">
          {block.items.map((item, ii) => (
            <li key={ii}>
              <span className="ocf-list-dot" />
              {item}
            </li>
          ))}
        </ul>
      );

    if (block.type === 'table')
      return (
        <div key={bi} className="ocf-table-wrap">
          <table className="ocf-table">
            <thead>
              <tr>{block.headers.map((h, hi) => <th key={hi}>{h}</th>)}</tr>
            </thead>
            <tbody>
              {block.rows.map((row, ri) => (
                <tr key={ri}>{row.map((cell, ci) => <td key={ci}>{cell}</td>)}</tr>
              ))}
            </tbody>
          </table>
        </div>
      );

    if (block.type === 'cards')
      return (
        <div key={bi} className="ocf-cards">
          {block.items.map((card, ci) => (
            <div key={ci} className="ocf-card">
              <span className="ocf-card-icon">{card.icon}</span>
              <strong>{card.title}</strong>
              <p>{card.desc}</p>
            </div>
          ))}
        </div>
      );

    if (block.type === 'steps')
      return (
        <div key={bi} className="ocf-steps">
          {block.items.map((s, si) => (
            <div key={si} className="ocf-step">
              <div className="ocf-step-num">{s.step}</div>
              <div className="ocf-step-body">
                <strong>{s.title}</strong>
                <p>{s.desc}</p>
              </div>
            </div>
          ))}
        </div>
      );

    if (block.type === 'contact')
      return (
        <div key={bi} className="ocf-contact-grid">
          {block.items.map((item, ii) => (
            <div key={ii} className="ocf-contact-item">
              <span className="ocf-contact-label">{item.label}</span>
              <strong className="ocf-contact-value">{item.value}</strong>
            </div>
          ))}
        </div>
      );

    return null;
  });

export default function PrivacyPolicy({ navigate }) {
  const [activeSection, setActiveSection] = useState('intro');
  const [scrolled, setScrolled] = useState(false);
  const mainRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    setActiveSection(id);
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  return (
    <div className="ocf-page">

      {/* ── TOP NAV BAR ── */}
      <header className={`ocf-topbar${scrolled ? ' ocf-topbar--scrolled' : ''}`}>
        <div className="ocf-topbar-inner">
          <button className="ocf-logo" onClick={() => navigate && navigate('home')}>
            <span className="ocf-logo-icon">⛽</span>
            <span>OnCallFuel</span>
          </button>
          <div className="ocf-topbar-right">
            <a href={`mailto:${PRIVACY_EMAIL}`} className="ocf-topbar-email">{PRIVACY_EMAIL}</a>
          </div>
        </div>
      </header>

      {/* ── HERO ── */}
      <section className="ocf-hero">
        <div className="ocf-hero-glow" />
        <div className="ocf-hero-grid-bg" />
        <div className="ocf-hero-inner">
          <div className="ocf-breadcrumb">
            <button onClick={() => navigate && navigate('home')}>Home</button>
            <span className="ocf-breadcrumb-sep">/</span>
            <span>Privacy Policy</span>
          </div>
          <div className="ocf-hero-badge">
            <span className="ocf-badge-dot" />
            DPDPA Compliant · IT Act 2000
          </div>
          <h1 className="ocf-hero-title">
            Privacy <span className="ocf-hero-accent">Policy</span>
          </h1>
          <p className="ocf-hero-sub">
            Your privacy is our priority. This policy transparently explains what data OnCallFuel collects,
            how we protect it, who we share it with, and the rights you hold over your information.
          </p>
          <div className="ocf-hero-pills">
            <span>📅 Effective: {EFFECTIVE_DATE}</span>
            <span>🔄 Updated: {LAST_UPDATED}</span>
            <span>🇮🇳 Indian Law Compliant</span>
            <span>🏢 {COMPANY_NAME}</span>
          </div>
        </div>
      </section>

      {/* ── LAYOUT ── */}
      <div className="ocf-layout" ref={mainRef}>

        {/* SIDEBAR TOC */}
        <aside className="ocf-toc">
          <p className="ocf-toc-title">Contents</p>
          <nav className="ocf-toc-nav">
            {SECTIONS.map((s) => (
              <button
                key={s.id}
                className={`ocf-toc-item${activeSection === s.id ? ' ocf-toc-item--active' : ''}`}
                onClick={() => scrollTo(s.id)}
              >
                <span className="ocf-toc-icon">{s.icon}</span>
                <span className="ocf-toc-label">{s.title}</span>
                {activeSection === s.id && <span className="ocf-toc-pip" />}
              </button>
            ))}
          </nav>
          <div className="ocf-toc-card">
            <p className="ocf-toc-card-title">Privacy Queries</p>
            <a href={`mailto:${PRIVACY_EMAIL}`}>{PRIVACY_EMAIL}</a>
            <p className="ocf-toc-card-response">Response within 30 days</p>
          </div>
        </aside>

        {/* MAIN CONTENT */}
        <main className="ocf-main">
          {SECTIONS.map((sec, si) => (
            <section
              key={sec.id}
              id={sec.id}
              className="ocf-section"
              style={{ animationDelay: `${si * 0.05}s` }}
            >
              <div className="ocf-section-header">
                <span className="ocf-section-icon">{sec.icon}</span>
                <h2 className="ocf-section-title">{sec.title}</h2>
                <span className="ocf-section-num">{String(si + 1).padStart(2, '0')}</span>
              </div>
              <div className="ocf-section-body">{renderContent(sec.content)}</div>
            </section>
          ))}

          {/* FOOTER NOTE */}
          <div className="ocf-footer-note">
            <div className="ocf-footer-note-left">
              <span className="ocf-footer-icon">⛽</span>
              <div>
                <strong>OnCallFuel — Privacy First</strong>
                <p>
                  {COMPANY_NAME} · {REGISTERED_OFFICE}
                </p>
              </div>
            </div>
            <div className="ocf-footer-note-right">
              <p>Effective {EFFECTIVE_DATE}</p>
              <a href={`mailto:${PRIVACY_EMAIL}`}>{PRIVACY_EMAIL}</a>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
